/**
 * ✅ Sheet6 값으로 실제 파일명 생성 (더 강력한 매칭)
 */
export const getActualFileName = (sheetValue) => {
  if (!sheetValue || typeof sheetValue !== 'string') {
    console.warn('❌ 유효하지 않은 시트 값:', sheetValue);
    return null;
  }
  
  const trimmedValue = sheetValue.trim();
  
  // 이미 확장자가 있는 경우 그대로 반환
  if (trimmedValue.includes('.')) {
    console.log(`🔄 확장자 포함 파일명: "${sheetValue}" → "${trimmedValue}"`);
    return trimmedValue;
  }
  
  // 확장자 추가 (.png)
  const actualFileName = `${trimmedValue}.png`;
  console.log(`🔄 파일명 변환: "${sheetValue}" → "${actualFileName}"`);
  
  return actualFileName;
};

/**
 * ✅ 2024년 Google Drive 정책 대응 - thumbnail URL 생성 (핵심 수정!)
 */
export const generateImageUrl = (fileId, method = 'thumbnail') => {
  if (!fileId) {
    console.warn('❌ 파일 ID가 없습니다');
    return null;
  }

  switch (method) {
    case 'thumbnail':
      // 🚨 2024년 정책 변경 대응: thumbnail 방식 사용
      return `https://drive.google.com/thumbnail?id=${fileId}&sz=w1000`;
    
    case 'uc_export':
      // 기존 방식 (2024년부터 CORS 문제 발생 가능)
      return `https://drive.google.com/uc?export=view&id=${fileId}`;
    
    case 'uc_id':
      // 구 방식 (deprecated)
      return `https://drive.google.com/uc?id=${fileId}`;
    
    default:
      return `https://drive.google.com/thumbnail?id=${fileId}&sz=w1000`;
  }
};

/**
 * ✅ Google Drive 폴더 스캔 (향상된 디버깅 버전)
 */
export const scanDriveFolder = async (apiKey) => {
  try {
    console.log('🔍 === Google Drive 폴더 스캔 시작 ===');
    console.log('📁 폴더 ID:', DRIVE_FOLDER_ID);
    console.log('🔑 API 키:', apiKey ? `${apiKey.substring(0, 10)}...` : '없음');
    
    if (!apiKey) {
      throw new Error('API 키가 제공되지 않았습니다.');
    }
    
    // Drive API v3 사용
    const url = `https://www.googleapis.com/drive/v3/files?q='${DRIVE_FOLDER_ID}'+in+parents&key=${apiKey}&fields=files(id,name,mimeType,webViewLink)&pageSize=1000`;
    console.log('🔗 API 요청 URL:', url);
    
    const response = await fetch(url);
    
    if (!response.ok) {
      const errorText = await response.text();
      console.error('❌ Drive API 응답 오류:', {
        status: response.status,
        statusText: response.statusText,
        errorText: errorText
      });
      
      // 구체적인 오류 메시지
      if (response.status === 403) {
        throw new Error('API 키 권한 문제: Google Drive API가 활성화되지 않았거나 권한이 부족합니다.');
      } else if (response.status === 404) {
        throw new Error('폴더를 찾을 수 없습니다: 폴더 ID가 잘못되었거나 접근 권한이 없습니다.');
      }
      
      throw new Error(`Drive API 오류: ${response.status} - ${errorText}`);
    }
    
    const data = await response.json();
    console.log('📁 폴더 스캔 원본 응답:', data);
    
    if (!data.files || data.files.length === 0) {
      console.warn('⚠️ 폴더에 파일이 없거나 접근할 수 없습니다.');
      console.log('💡 확인사항:');
      console.log('   1. 폴더 ID가 정확한지 확인');
      console.log('   2. 폴더가 공개 상태인지 확인');
      console.log('   3. API 키가 유효한지 확인');
      console.log('   4. Google Drive API가 활성화되어 있는지 확인');
      return false;
    }
    
    console.log(`📊 전체 파일 수: ${data.files.length}개`);
    
    // 모든 파일 목록 출력 (디버깅용)
    data.files.forEach((file, index) => {
      console.log(`📄 파일 ${index + 1}: "${file.name}" (${file.mimeType}) ID: ${file.id}`);
    });
    
    // 이미지 파일만 필터링 (더 강력한 필터링)
    const imageFiles = data.files.filter(file => {
      const mimeType = file.mimeType || '';
      const fileName = file.name || '';
      
      const isImageMimeType = mimeType.startsWith('image/');
      const isImageExtension = /\.(jpg|jpeg|png|gif|webp|bmp|svg)$/i.test(fileName);
      const isPartFile = /^Part\s*[23]-\d+\.png$/i.test(fileName);
      
      const isImage = isImageMimeType || isImageExtension || isPartFile;
      
      if (isImage) {
        console.log(`🖼️ 이미지 파일 발견: "${fileName}" (${mimeType})`);
      }
      
      return isImage;
    });
    
    console.log(`🖼️ 발견된 이미지 파일: ${imageFiles.length}개`);
    
    if (imageFiles.length === 0) {
      console.warn('⚠️ 이미지 파일이 없습니다.');
      console.log('📋 전체 파일 이름들:', data.files.map(f => f.name));
      return false;
    }
    
    // fileIdMap 자동 업데이트 (더 유연한 매칭)
    let mappedCount = 0;
    let unmappedFiles = [];
    
    imageFiles.forEach(file => {
      const fileName = file.name;
      
      // 직접 매칭 시도
      if (fileIdMap.hasOwnProperty(fileName)) {
        fileIdMap[fileName] = file.id;
        mappedCount++;
        console.log(`✅ 직접 매칭: "${fileName}" → ${file.id}`);
      } else {
        // 유연한 매칭 시도 (공백, 대소문자 무시)
        const normalizedFileName = fileName.toLowerCase().replace(/\s+/g, '');
        let matched = false;
        
        for (const key of Object.keys(fileIdMap)) {
          const normalizedKey = key.toLowerCase().replace(/\s+/g, '');
          if (normalizedKey === normalizedFileName) {
            fileIdMap[key] = file.id;
            mappedCount++;
            matched = true;
            console.log(`✅ 유연한 매칭: "${fileName}" → "${key}" → ${file.id}`);
            break;
          }
        }
        
        if (!matched) {
          unmappedFiles.push(fileName);
          console.log(`⚠️ 매핑되지 않은 파일: "${fileName}"`);
        }
      }
    });
    
    // 매핑 결과 상세 출력
    console.log('📋 === 매핑 결과 ===');
    console.log(`✅ 성공적으로 매핑된 파일: ${mappedCount}개`);
    console.log(`⚠️ 매핑되지 않은 파일: ${unmappedFiles.length}개`);
    
    if (unmappedFiles.length > 0) {
      console.log('📋 매핑되지 않은 파일들:', unmappedFiles);
    }
    
    // 매핑되지 않은 fileIdMap 키들 확인
    const unmappedKeys = Object.keys(fileIdMap).filter(key => !fileIdMap[key]);
    if (unmappedKeys.length > 0) {
      console.log('📋 매핑되지 않은 키들 (처음 10개):', unmappedKeys.slice(0, 10));
    }
    
    console.log(`🎯 자동 스캔 완료! ${mappedCount}개 파일 매핑됨 (총 ${Object.keys(fileIdMap).length}개 중)`);
    
    // 성공 기준: 최소 5개 이상 매핑되면 성공으로 간주
    const success = mappedCount >= 5;
    if (!success) {
      console.warn(`⚠️ 매핑된 파일이 너무 적습니다 (${mappedCount}개). 폴더 구조나 파일명을 확인해주세요.`);
    }
    
    return success;
    
  } catch (error) {
    console.error('❌ Drive 폴더 스캔 실패:', error);
    console.error('상세 오류:', {
      name: error.name,
      message: error.message,
      stack: error.stack
    });
    return false;
  }
};

/**
 * ✅ 파일명으로 Google Drive 이미지 URL 생성 (2024년 정책 대응 완료)
 */
export const getImageUrl = async (sheetImageValue, apiKey = null) => {
  console.log('🖼️ === getImageUrl 시작 (2024년 정책 대응) ===');
  console.log('📝 입력 시트 값:', sheetImageValue);
  
  if (!sheetImageValue || typeof sheetImageValue !== 'string') {
    console.warn('❌ 유효하지 않은 시트 이미지 값:', sheetImageValue);
    return null;
  }

  // 1. Sheet6 값을 실제 파일명으로 변환
  const actualFileName = getActualFileName(sheetImageValue);
  if (!actualFileName) {
    console.warn(`⚠️ 파일명 변환 실패: "${sheetImageValue}"`);
    return null;
  }
  
  console.log('📂 변환된 파일명:', actualFileName);
  
  // 2. fileIdMap에서 직접 ID 찾기 (완전 매핑되어 있음)
  let fileId = fileIdMap[actualFileName];
  console.log('🔍 fileIdMap에서 찾은 ID:', fileId);
  
  // 3. 유사한 파일명으로 재시도 (대소문자나 공백 차이 대응)
  if (!fileId) {
    console.log('🔄 유사한 파일명으로 재검색 시도...');
    
    const normalizedInput = actualFileName.toLowerCase().replace(/\s+/g, '');
    
    for (const [mappedFileName, mappedFileId] of Object.entries(fileIdMap)) {
      const normalizedMapped = mappedFileName.toLowerCase().replace(/\s+/g, '');
      
      if (normalizedMapped === normalizedInput && mappedFileId) {
        fileId = mappedFileId;
        console.log(`✅ 유사 매칭 성공: "${actualFileName}" → "${mappedFileName}" → ${fileId}`);
        break;
      }
    }
  }
  
  if (!fileId) {
    console.warn(`⚠️ 파일 ID를 찾을 수 없습니다: "${actualFileName}"`);
    
    // 디버깅: 매핑된 파일들 중 유사한 것 찾기
    const similarFiles = Object.keys(fileIdMap).filter(key => 
      key.toLowerCase().includes(sheetImageValue.toLowerCase()) ||
      sheetImageValue.toLowerCase().includes(key.toLowerCase().replace('.png', ''))
    );
    
    if (similarFiles.length > 0) {
      console.log('🔍 유사한 파일명들:', similarFiles);
      
      // 첫 번째 유사 파일 사용
      const firstSimilar = similarFiles[0];
      const firstSimilarId = fileIdMap[firstSimilar];
      if (firstSimilarId) {
        console.log(`🔄 첫 번째 유사 파일 사용: ${firstSimilar}`);
        fileId = firstSimilarId;
      }
    }
    
    if (!fileId) {
      // 최종적으로 매핑된 파일 목록 출력 (디버깅용)
      const mappedFiles = Object.keys(fileIdMap).filter(key => fileIdMap[key]);
      console.log('📋 현재 매핑된 파일들 (처음 10개):', mappedFiles.slice(0, 10));
      return null;
    }
  }

  // 4. 🚨 2024년 Google Drive 정책 대응: thumbnail URL 생성
  const imageUrl = generateImageUrl(fileId, 'thumbnail');
  console.log(`✅ 이미지 URL 생성 성공 (2024년 정책 대응):`);
  console.log(`   시트값: "${sheetImageValue}"`);
  console.log(`   파일명: "${actualFileName}"`);
  console.log(`   파일ID: "${fileId}"`);
  console.log(`   URL: "${imageUrl}"`);
  console.log(`   방식: thumbnail (CORS 문제 해결)`);
  
  return imageUrl;
};

