export const getAllFileMappings = () => {
  const validMappings = {};
  Object.entries(fileIdMap).forEach(([filename, fileId]) => {
    if (fileId && fileId !== null) {
      validMappings[filename] = fileId;
    }
  });
  return validMappings;
};

export const hasFileMapping = (filename) => {
  return Boolean(filename && fileIdMap[filename.trim()] && fileIdMap[filename.trim()] !== null);
};

export const addFileMapping = (filename, fileId) => {
  if (!filename || !fileId) {
    console.error('❌ 파일명과 파일 ID가 모두 필요합니다.');
    return false;
  }

  fileIdMap[filename.trim()] = fileId.trim();
  console.log(`✅ 새 파일 매핑 추가: ${filename} → ${fileId}`);
  return true;
};

/**
 * ✅ 2024년 정책 확인 함수
 */
export const check2024Policy = async () => {
  console.log('🔍 === 2024년 Google Drive 정책 확인 ===');
  
  // 테스트용 파일 ID 사용
  const testFileId = Object.values(fileIdMap).find(id => id !== null);
  if (!testFileId) {
    console.warn('⚠️ 테스트할 파일 ID가 없습니다.');
    return false;
  }
  
  const oldUrl = generateImageUrl(testFileId, 'uc_export');
  const newUrl = generateImageUrl(testFileId, 'thumbnail');
  
  console.log('🧪 구 방식 테스트:', oldUrl);
  const oldWorks = await testImageUrl(oldUrl);
  
  console.log('🧪 신 방식 테스트:', newUrl);
  const newWorks = await testImageUrl(newUrl);
  
  console.log('📊 테스트 결과:');
  console.log(`   구 방식 (uc): ${oldWorks ? '✅ 작동' : '❌ 실패'}`);
  console.log(`   신 방식 (thumbnail): ${newWorks ? '✅ 작동' : '❌ 실패'}`);
  
  if (!oldWorks && newWorks) {
    console.log('🎯 2024년 정책 변경 확인됨 - thumbnail 방식 사용 권장');
  } else if (oldWorks && newWorks) {
    console.log('✅ 두 방식 모두 작동 - 안정성을 위해 thumbnail 사용 권장');
  } else if (!newWorks) {
    console.warn('⚠️ 신 방식도 실패 - 네트워크나 권한 문제 확인 필요');
  }
  
  return newWorks;
};

