// fetchGoogleSheet.js - 한국어, 일본어, 중국어 Part 2/3 모두 Sheet6에서 가져오기

const getSheetRange = (language) => {
  const sheetMap = {
    'korean': 'Sheet1!A:G',
    'japanese': 'Sheet2!A:G',
    'english': 'Sheet3!A:G',        // 기본 영어
    'englishexpress': 'Sheet3!A:G', // Express는 Sheet3
    'englishelite': 'Sheet4!A:G',   // Elite는 Sheet4
    'chinese': 'Sheet5!A:G',
    'sheet6': 'Sheet6!A:H'          // ✅ Sheet6 추가 (H열까지 - Image 컬럼 포함)
  };
  
  console.log(`🗺️ 언어 매핑 시도: ${language}`);
  
  // 언어 정규화 및 매핑
  let mappedLanguage = language?.toLowerCase().trim();
  
  // ✅ 직접 매핑 확인
  const range = sheetMap[mappedLanguage];
  
  if (!range) {
    console.warn(`⚠️ 매핑되지 않은 언어: ${language} (${mappedLanguage})`);
    console.log(`🔍 사용 가능한 언어들:`, Object.keys(sheetMap));
    return 'Sheet1!A:G'; // 기본값으로 한국어 시트 사용
  }
  
  console.log(`✅ 최종 매핑: ${language} → ${mappedLanguage} → ${range}`);
  
  return range;
};

