/**
 * ✅ 파트별 문제 필터링 (한국어도 Sheet6 사용하도록 수정)
 * @param {Array} sheetData - 전체 시트 데이터
 * @param {string} language - 언어
 * @param {string} level - 난이도 (beginner, intermediate, advanced)
 * @param {number} part - 파트 번호
 * @returns {Array} 필터링된 문제들
 */
export const filterQuestionsByPart = (sheetData, language, level, part) => {
  if (!sheetData || !Array.isArray(sheetData)) {
    console.warn('⚠️ 시트 데이터가 유효하지 않습니다.');
    return [];
  }

  console.log(`🔍 필터링 조건: ${language} ${level} Part ${part}`);
  console.log(`📊 전체 시트 데이터 수: ${sheetData.length}`);

  const filtered = sheetData.filter(item => {
    const itemLanguage = item.language?.trim();
    const itemLevel = item.level?.toLowerCase().trim();
    const itemPart = parseInt(item.part);

    // ✅ 언어 매칭 로직 개선 (한국어도 Sheet6 사용)
    let languageMatch = false;
    
    // 🚨 Part 2, 3의 경우: 한국어, 일본어, 중국어 모두 Sheet6 방식 사용
    if (part === 2 || part === 3) {
      if (language === 'korean') {
        // 한국어: Sheet6에서 한국어 데이터 매칭
        languageMatch = itemLanguage?.toLowerCase() === 'korean' ||
                       itemLanguage?.toLowerCase() === '한국어' ||
                       itemLanguage?.toLowerCase() === 'ko' ||
                       itemLanguage?.toLowerCase() === 'kor';
      } else if (language === 'japanese') {
        languageMatch = itemLanguage?.toLowerCase() === 'japanese' ||
                       itemLanguage?.toLowerCase() === '日本語' ||
                       itemLanguage?.toLowerCase() === 'ja' ||
                       itemLanguage?.toLowerCase() === 'jpn';
      } else if (language === 'chinese') {
        languageMatch = itemLanguage?.toLowerCase() === 'chinese' ||
                       itemLanguage?.toLowerCase() === '中文' ||
                       itemLanguage?.toLowerCase() === 'zh' ||
                       itemLanguage?.toLowerCase() === 'chn';
      } else if (language === 'englishexpress') {
        // 영어 Express: Sheet3에서 가져온 데이터
        languageMatch = itemLanguage?.toLowerCase() === 'english express' ||
                       itemLanguage?.toLowerCase() === 'englishexpress' ||
                       itemLanguage?.toLowerCase() === 'english';
      } else if (language === 'englishelite') {
        // 영어 Elite: Sheet4에서 가져온 데이터
        const eliteVariants = [
          'english elite',
          'englishelite', 
          'elite',
          'english interview',
          'interview',
          'english_elite',
          'e-interview elite',
          'english (elite)',
          'english-elite'
        ];
        
        languageMatch = eliteVariants.some(variant => 
          itemLanguage?.toLowerCase() === variant ||
          itemLanguage?.toLowerCase().includes(variant.split(' ')[0])
        );
        
        if (!languageMatch && itemLanguage?.toLowerCase() === 'english') {
          languageMatch = true;
        }
      } else {
        // 기타 언어
        languageMatch = itemLanguage?.toLowerCase() === language.toLowerCase();
      }
    } else {
      // 기존 로직 (다른 Part들)
      if (language === 'korean') {
        languageMatch = itemLanguage?.toLowerCase() === 'korean' ||
                       itemLanguage?.toLowerCase() === '한국어' ||
                       itemLanguage?.toLowerCase() === 'ko' ||
                       itemLanguage?.toLowerCase() === 'kor';
      } else if (language === 'englishexpress') {
        languageMatch = itemLanguage?.toLowerCase() === 'english express' ||
                       itemLanguage?.toLowerCase() === 'englishexpress' ||
                       itemLanguage?.toLowerCase() === 'english';
      } else if (language === 'englishelite') {
        const eliteVariants = [
          'english elite',
          'englishelite', 
          'elite',
          'english interview',
          'interview',
          'english_elite',
          'e-interview elite',
          'english (elite)',
          'english-elite'
        ];
        
        languageMatch = eliteVariants.some(variant => 
          itemLanguage?.toLowerCase() === variant ||
          itemLanguage?.toLowerCase().includes(variant.split(' ')[0])
        );
        
        if (!languageMatch && itemLanguage?.toLowerCase() === 'english') {
          languageMatch = true;
        }
      } else {
        languageMatch = itemLanguage?.toLowerCase() === language.toLowerCase();
      }
    }

    const levelMatch = itemLevel === level.toLowerCase();
    const partMatch = itemPart === part;

    const matches = languageMatch && levelMatch && partMatch;
    
    if (matches) {
      console.log(`✅ 매칭 성공: ${item.question?.substring(0, 50)}...`);
    }

    return matches;
  });

  console.log(`🎯 필터링 결과: ${language} ${level} Part ${part} → ${filtered.length}개 문항`);
  
  return filtered;
};

/**
 * 랜덤 문제 선택
 * @param {Array} questions - 필터링된 문제들
 * @param {Array} usedQuestions - 이미 사용된 문제들
 * @returns {Object|null} 선택된 문제
 */
export const selectRandomQuestion = (questions, usedQuestions = []) => {
  if (!questions || questions.length === 0) {
    console.warn('⚠️ 선택할 수 있는 문제가 없습니다.');
    return null;
  }

  // 이미 사용된 문제 제외
  const availableQuestions = questions.filter(q => 
    !usedQuestions.some(used => used.question === q.question)
  );

  if (availableQuestions.length === 0) {
    console.warn('⚠️ 모든 문제를 사용했습니다. 처음부터 다시 시작합니다.');
    // 모든 문제를 다 써버린 경우 전체에서 다시 선택
    const randomIndex = Math.floor(Math.random() * questions.length);
    return questions[randomIndex];
  }

  const randomIndex = Math.floor(Math.random() * availableQuestions.length);
  const selected = availableQuestions[randomIndex];
  
  console.log('🎲 선택된 문제:', selected.question);
  return selected;
};

/**
 * 문제 데이터를 AITestMode 형식으로 변환
 * @param {Object} sheetQuestion - 시트에서 가져온 문제
 * @param {number} testPart - 파트 번호
 * @param {Object} mockTestData - 테스트 설정 데이터
 * @returns {Object} AITestMode 호환 문제 객체
 */
export const convertToTestFormat = (sheetQuestion, testPart, mockTestData) => {
  if (!sheetQuestion) {
    return null;
  }

  const currentPart = mockTestData?.parts?.[testPart - 1];
  
  return {
    id: Date.now(),
    part: testPart,
    partName: currentPart?.name || `Part ${testPart}`,
    text: sheetQuestion.question || '',
    sample: sheetQuestion.model_answer || '',
    showSample: sheetQuestion.show_model_answer?.toLowerCase() === 'yes',
    category: '시트_문제', // 시트에서 가져온 문제 표시
    difficulty: sheetQuestion.level || 'intermediate',
    answerTime: currentPart?.answerTime || 60,
    source: 'google_sheets',
    image: sheetQuestion.image || null  // ✅ 이미지 필드 추가
  };
};

/**
 * 문제 데이터 검증
 * @param {Object} question - 검증할 문제
 * @returns {Object} 검증 결과
 */
export const validateSheetQuestion = (question) => {
  const errors = [];
  
  if (!question) {
    errors.push('문제 데이터가 없습니다.');
    return { isValid: false, errors };
  }

  if (!question.question || question.question.trim() === '') {
    errors.push('질문 텍스트가 없습니다.');
  }

  if (!question.language || question.language.trim() === '') {
    errors.push('언어 정보가 없습니다.');
  }

  if (!question.level || question.level.trim() === '') {
    errors.push('난이도 정보가 없습니다.');
  }

  if (!question.part || isNaN(parseInt(question.part))) {
    errors.push('파트 정보가 유효하지 않습니다.');
  }

  const partNum = parseInt(question.part);
  if (partNum < 1 || partNum > 8) {
    errors.push('파트 번호는 1-8 사이여야 합니다.');
  }

  return {
    isValid: errors.length === 0,
    errors
  };
};

/**
 * 시트 데이터 통계 정보
 * @param {Array} sheetData - 전체 시트 데이터
 * @returns {Object} 통계 정보
 */
export const getSheetDataStats = (sheetData) => {
  if (!sheetData || !Array.isArray(sheetData)) {
    return {
      total: 0,
      byLanguage: {},
      byLevel: {},
      byPart: {},
      validQuestions: 0,
      invalidQuestions: 0
    };
  }

  const stats = {
    total: sheetData.length,
    byLanguage: {},
    byLevel: {},
    byPart: {},
    validQuestions: 0,
    invalidQuestions: 0
  };

  sheetData.forEach(item => {
    const validation = validateSheetQuestion(item);
    
    if (validation.isValid) {
      stats.validQuestions++;
      
      // 언어별 통계
      const lang = item.language?.toLowerCase() || 'unknown';
      stats.byLanguage[lang] = (stats.byLanguage[lang] || 0) + 1;
      
      // 난이도별 통계
      const level = item.level?.toLowerCase() || 'unknown';
      stats.byLevel[level] = (stats.byLevel[level] || 0) + 1;
      
      // 파트별 통계
      const part = parseInt(item.part) || 0;
      stats.byPart[part] = (stats.byPart[part] || 0) + 1;
    } else {
      stats.invalidQuestions++;
    }
  });

  return stats;
};

/**
 * 캐시된 시트 데이터 관리
 */
const sheetDataCache = new Map();

export const cacheSheetData = (key, data) => {
  sheetDataCache.set(key, {
    data,
    timestamp: Date.now(),
    ttl: 1000 * 60 * 30 // 30분 TTL
  });
};

export const getCachedSheetData = (key) => {
  const cached = sheetDataCache.get(key);
  if (!cached) return null;
  
  const now = Date.now();
  if (now - cached.timestamp > cached.ttl) {
    sheetDataCache.delete(key);
    return null;
  }
  
  return cached.data;
};

export const clearSheetDataCache = () => {
  sheetDataCache.clear();
};

/**
 * ✅ Google Sheets 문제 로더 클래스 (한국어도 Sheet6 사용하도록 수정)
 */
export class GoogleSheetsQuestionLoader {
  constructor(apiKey, sheetId) {
    this.apiKey = apiKey;
    this.sheetId = sheetId;
    this.cachedDataBySheet = new Map();
    this.sheet6Data = null; // ✅ Sheet6 전용 캐시 (한국어, 일본어, 중국어)
    this.lastFetch = null;
    this.usedQuestions = new Map();
    this.initialized = false;
  }

  async loadData(language = 'korean', forceRefresh = false) {
    // ✅ Sheet6 데이터도 함께 로드 (한국어, 일본어, 중국어용)
    await this.loadSheet6Data(forceRefresh);
    
    // 기존 로직 유지
    const cacheKey = `${this.sheetId}_${this.apiKey.substring(0, 8)}_all_sheets`;
    
    if (!forceRefresh) {
      const cached = getCachedSheetData(cacheKey);
      if (cached) {
        console.log('📋 캐시된 전체 시트 데이터 사용');
        this.cachedDataBySheet.set('all', cached);
        this.initialized = true;
        return cached;
      }
    }

    console.log(`🔄 모든 Google Sheets 데이터 로드 시작`);
    
    try {
      const allSheetData = [];
      
      const sheetsToLoad = [
        { lang: 'korean', name: 'Korean(Sheet1)' },
        { lang: 'japanese', name: 'Japanese(Sheet2)' },
        { lang: 'englishexpress', name: 'English Express(Sheet3)' },
        { lang: 'englishelite', name: 'English Elite(Sheet4)' },
        { lang: 'chinese', name: 'Chinese(Sheet5)' }
      ];
      
      for (const sheet of sheetsToLoad) {
        try {
          console.log(`📊 ${sheet.name} 로드 시도 중...`);
          const sheetData = await fetchSheetData(this.apiKey, this.sheetId, sheet.lang);
          
          if (sheetData && sheetData.length > 0) {
            console.log(`✅ ${sheet.name} 로드 성공: ${sheetData.length}개 문항`);
            allSheetData.push(...sheetData);
          } else {
            console.warn(`⚠️ ${sheet.name}: 데이터가 없습니다`);
          }
          
        } catch (sheetError) {
          console.warn(`⚠️ ${sheet.name} 로드 실패:`, sheetError.message);
          continue;
        }
      }
      
      // ✅ Sheet6 데이터도 전체 데이터에 추가 (한국어, 일본어, 중국어 Part 2, 3)
      if (this.sheet6Data && this.sheet6Data.length > 0) {
        console.log(`📊 Sheet6 데이터 추가: ${this.sheet6Data.length}개`);
        allSheetData.push(...this.sheet6Data);
      }
      
      if (allSheetData.length === 0) {
        throw new Error('모든 시트에서 데이터를 로드할 수 없습니다.');
      }
      
      cacheSheetData(cacheKey, allSheetData);
      this.cachedDataBySheet.set('all', allSheetData);
      this.lastFetch = Date.now();
      this.initialized = true;
      
      console.log('✅ 전체 시트 데이터 로드 성공:', allSheetData.length, '개 문항');
      
      return allSheetData;
      
    } catch (error) {
      console.error('❌ 시트 데이터 로드 완전 실패:', error);
      this.initialized = false;
      throw error;
    }
  }

  // ✅ Sheet6 전용 로드 함수 (한국어, 일본어, 중국어)
  async loadSheet6Data(forceRefresh = false) {
    if (!forceRefresh && this.sheet6Data) {
      console.log('📋 캐시된 Sheet6 데이터 사용');
      return this.sheet6Data;
    }

    try {
      console.log('🔄 Sheet6 데이터 로드 시작...');
      this.sheet6Data = await fetchSheet6Data(this.apiKey, this.sheetId);
      console.log(`✅ Sheet6 로드 완료: ${this.sheet6Data.length}개 문항`);
      return this.sheet6Data;
    } catch (error) {
      console.error('❌ Sheet6 로드 실패:', error);
      this.sheet6Data = [];
      return [];
    }
  }

  async getQuestion(language, level, part) {
    if (!this.initialized) {
      console.log('🔄 시트 데이터 초기화 중...');
      await this.loadData(language);
    }

    let dataSource;
    
    // ✅ 🚨 핵심 수정: Part 2, 3인 경우 언어별 분기 (한국어도 Sheet6 사용)
    if (part === 2 || part === 3) {
      if (language === 'korean' || language === 'japanese' || language === 'chinese') {
        console.log(`🎯 Part ${part} ${language} → Sheet6 데이터 사용`);
        dataSource = this.sheet6Data || [];
      } else {
        console.log(`🎯 Part ${part} ${language} → 기존 시트 데이터 사용`);
        dataSource = this.cachedDataBySheet.get('all') || [];
      }
    } else {
      // 기존 방식
      dataSource = this.cachedDataBySheet.get('all') || [];
    }
    
    if (dataSource.length === 0) {
      console.warn('⚠️ 로드된 시트 데이터가 없습니다.');
      return null;
    }

    console.log(`🔍 질문 검색: ${language} ${level} Part ${part}`);
    console.log(`📊 사용할 데이터 수: ${dataSource.length}`);

    const filtered = filterQuestionsByPart(dataSource, language, level, part);
    
    if (filtered.length === 0) {
      console.warn(`⚠️ ${language} ${level} Part ${part}에 사용 가능한 문제가 없습니다.`);
      return null;
    }

    const sessionKey = `${language}_${level}_${part}`;
    const usedInSession = this.usedQuestions.get(sessionKey) || [];
    
    const selected = selectRandomQuestion(filtered, usedInSession);
    
    if (selected) {
      usedInSession.push(selected);
      this.usedQuestions.set(sessionKey, usedInSession);
      console.log('✅ 문제 선택 완료:', selected.question);
    }

    return selected;
  }

  resetUsedQuestions(language, level, part) {
    const sessionKey = `${language}_${level}_${part}`;
    this.usedQuestions.delete(sessionKey);
  }

  resetAllUsedQuestions() {
    this.usedQuestions.clear();
  }

  getStats() {
    const allData = this.cachedDataBySheet.get('all');
    if (!allData) {
      return null;
    }
    return getSheetDataStats(allData);
  }

  isInitialized() {
    return this.initialized && this.cachedDataBySheet.get('all') && this.cachedDataBySheet.get('all').length > 0;
  }
}

// 싱글톤 인스턴스 (필요시 사용)
let globalQuestionLoader = null;

export const initializeQuestionLoader = (apiKey, sheetId) => {
  console.log('🚀 QuestionLoader 초기화 시작');
  globalQuestionLoader = new GoogleSheetsQuestionLoader(apiKey, sheetId);
  return globalQuestionLoader;
};

export const getQuestionLoader = () => {
  if (!globalQuestionLoader) {
    throw new Error('QuestionLoader가 초기화되지 않았습니다. initializeQuestionLoader를 먼저 호출하세요.');
  }
  return globalQuestionLoader;
};

/**
 * ✅ 연결 테스트 함수 (디버깅용)
 */
export const testSheetConnection = async (apiKey, sheetId) => {
  try {
    console.log('🧪 Google Sheets 연결 테스트 시작');
    
    const data = await fetchSheetData(apiKey, sheetId, 'korean');
    const stats = getSheetDataStats(data);
    
    return {
      success: true,
      message: '연결 성공!',
      dataCount: data.length,
      stats: stats,
      sampleData: data.slice(0, 3)
    };
  } catch (error) {
    return {
      success: false,
      message: error.message,
      error: error
    };
  }
};

