/**
 * 피드백 섹션 추출 헬퍼 함수
 * @param {string} feedbackText - 피드백 텍스트
 * @param {string} sectionHeader - 섹션 헤더
 * @returns {string} 추출된 섹션 HTML
 */
function extractFeedbackSection(feedbackText, sectionHeader) {
  if (!feedbackText) return '<p>정보를 찾을 수 없습니다.</p>';
  
  const sections = feedbackText.split(/[①-⑧][^:]*:/);
  const headers = feedbackText.match(/[①-⑧][^:]*/g) || [];
  
  const index = headers.findIndex(header => header.includes(sectionHeader.replace(':', '')));
  
  if (index !== -1 && index + 1 < sections.length) {
    return sections[index + 1].trim()
      .replace(/\*\*(.*?)\*\*/g, '<strong class="error-highlight">$1</strong>')
      .replace(/\*(.*?)\*/g, '<em>$1</em>')
      .replace(/\n/g, '<br>');
  }
  
  return '<p>정보를 찾을 수 없습니다.</p>';
}

