// 권한 확인
const checkMicrophonePermission = async () => {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    console.log('✅ 마이크 권한 확인됨');
    stream.getTracks().forEach(track => track.stop());
    return true;
  } catch (error) {
    console.error('❌ 마이크 권한 오류:', error);
    return false;
  }
};

// 소스 언어 자동 감지
const detectSourceLanguage = (text) => {
  if (!text) return 'auto';
  
  if (/[\u3040-\u309F\u30A0-\u30FF]/.test(text)) {
    return 'ja';
  } else if (/[\uAC00-\uD7AF]/.test(text)) {
    return 'ko';
  } else if (/[\u4E00-\u9FFF]/.test(text) && !/[\u3040-\u309F\u30A0-\u30FF]/.test(text)) {
    return 'zh';
  } else if (/^[a-zA-Z\s.,!?'"()-]+$/.test(text.trim())) {
    return 'en';
  }
  
  return 'auto';
};

// 번역 함수
const translateText = async (text, targetLang, apiKey = null) => {
  if (!text || !targetLang) return text;
  
  const sourceLang = detectSourceLanguage(text);
  
  if (sourceLang === targetLang) {
    return text;
  }
  
  try {
    if (apiKey && apiKey.trim()) {
      try {
        const response = await fetch(`https://translation.googleapis.com/language/translate/v2?key=${apiKey}`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            q: text,
            target: targetLang,
            source: sourceLang === 'auto' ? undefined : sourceLang,
            format: 'text'
          })
        });
        
        if (response.ok) {
          const data = await response.json();
          const translatedText = data.data.translations[0].translatedText;
          console.log(`Google Translate: ${sourceLang} -> ${targetLang}:`, translatedText);
          return translatedText;
        }
      } catch (googleError) {
        console.warn('Google Translate error:', googleError);
      }
    }
    
    const langPair = sourceLang === 'auto' ? `auto|${targetLang}` : `${sourceLang}|${targetLang}`;
    const response = await fetch(`https://api.mymemory.translated.net/get?q=${encodeURIComponent(text)}&langpair=${langPair}`);
    const data = await response.json();
    
    if (data.responseStatus === 200 && data.responseData.translatedText) {
      const translatedText = data.responseData.translatedText;
      console.log(`MyMemory Translate: ${langPair}:`, translatedText);
      return translatedText;
    }
    
    return text;
    
  } catch (error) {
    console.error('Translation error:', error);
    return text;
  }
};

