                    display: 'flex',
                    alignItems: 'center',
                    gap: 'var(--space-sm)',
                    padding: 'var(--space-lg) var(--space-2xl)',
                    background: (isAndroid && !microphoneReady) ? 'rgba(102, 126, 234, 0.6)' : 'var(--success-gradient)',
