              gap: 'var(--space-sm)',
              padding: 'var(--space-lg) var(--space-2xl)',
              background: 'var(--warning-gradient)',
              border: 'none',
              borderRadius: 'var(--radius-lg)',
              color: 'var(--bg-main)',
              fontSize: '1.1rem',
              fontWeight: '700',
              cursor: 'pointer',
              boxShadow: 'var(--shadow-lg)',
              flex: isMobile ? '1 1 100%' : 'none'
