// questionGenerator.js - 질문 생성 및 관리 모듈

import { mockTestData, languageData, logInfo, API_CONFIG } from './testConfig.js';

/**
 * 파트별 특성에 맞는 질문 프롬프트 생성 함수
 * @param {string} testType - 테스트 유형
 * @param {number} testPart - 현재 파트 번호
 * @returns {string} 파트별 특성 프롬프트
 */
export const getPartSpecificPrompt = (testType, testPart) => {
  const currentTest = mockTestData[testType];
  const currentPart = currentTest.parts[testPart - 1];
  
  let partSpecificPrompt = '';
  
  switch(testPart) {
    case 1: // 자기소개 파트
      partSpecificPrompt = `이 파트는 자기소개와 관련된 기본적인 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 이름, 직업, 취미, 가족 등 개인적인 기본 정보를 묻는 질문
      - 간단한 일상 활동이나 선호도에 대한 질문
      - 학교/직장/거주지 등에 대한 기본적인 질문
      
      질문 예시:
      - "취미가 무엇인지 말씀해 주세요."
      - "가족에 대해 간단히 소개해 주세요."
      - "어떤 일을 하고 계신가요?"`;
      break;
      
    case 2: // 일상생활 파트
      partSpecificPrompt = `이 파트는 일상생활에 대한 구체적인 묘사를 요구하는 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 일상 활동의 구체적인 설명을 요청하는 질문
      - 특정 상황이나 활동에 대한 선호도나 빈도를 묻는 질문
      - 일상 루틴이나 습관에 대한 질문
      
      질문 예시:
      - "주말에 주로 어떤 활동을 하는지 설명해 주세요."
      - "아침 루틴에 대해 설명해 주세요."
      - "평일 저녁 시간을 어떻게 보내는지 설명해 주세요."`;
      break;
      
    case 3: // 상황대처 파트
      partSpecificPrompt = `이 파트는 특정 상황이나 문제에 대한 대처 방법을 설명하는 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 일상적인 문제 상황에 대한 대처 방법을 묻는 질문
      - 특정 갈등이나 어려움에 대한 해결책을 요구하는 질문
      - 예상치 못한 상황에 대한 반응을 묻는 질문
      
      질문 예시:
      - "식당에서 주문한 음식이 잘못 나왔을 때 어떻게 하시겠습니까?"
      - "기차나 비행기를 놓쳤을 때 어떻게 대처하시겠습니까?"
      - "직장/학교에서 중요한 마감일을 놓쳤을 때 어떻게 하시겠습니까?"`;
      break;
      
    case 4: // 일상대화 파트
      partSpecificPrompt = `이 파트는 일상적인 대화 주제에 대한 깊이 있는 의견이나 설명을 요구하는 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 일상적 주제에 대한 더 깊이 있는 대화를 유도하는 질문
      - 개인 경험이나 기억에 관한 질문
      - 선호도와 그 이유를 함께 묻는 질문
      
      질문 예시:
      - "가장 기억에 남는 여행 경험에 대해 이야기해 주세요."
      - "좋아하는 음식과 그 이유에 대해 설명해 주세요."
      - "여가 시간에 즐겨 하는 활동과 그것이 왜 중요한지 설명해 주세요."`;
      break;
      
    case 5: // 의견표현 파트
      partSpecificPrompt = `이 파트는 사회적 또는 추상적인 주제에 대한 개인적인 의견을 묻는 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 사회 문제나 추세에 대한 의견을 요구하는 질문
      - 문화적 차이나 변화에 대한 관점을 묻는 질문
      - 가치관이나 신념에 관한 질문
      
      질문 예시:
      - "최근 청년 실업 문제에 대한 의견을 말씀해 주세요."
      - "온라인 교육과 전통적인 교육 방식 중 어떤 것이 더 효과적이라고 생각하십니까?"
      - "지속 가능한 환경을 위해 개인이 할 수 있는 일은 무엇이라고 생각하십니까?"`;
      break;
      
    case 6: // 역할극 파트
      partSpecificPrompt = `이 파트는 특정 상황에서의 대화나 역할극을 요구하는 질문입니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 특정 상황에서의 대화를 요청하는 질문 (예: 가게에서, 면접에서)
      - 특정 역할을 맡아 대화하도록 요청하는 질문
      - 실제 생활에서 발생할 수 있는 특정 대화 상황을 설정하는 질문
      
      질문 예시:
      - "호텔 프론트 데스크에서 방을 예약하는 상황을 연기해 주세요."
      - "직장 면접에서 자신의 강점을 설명하는 상황을 연기해 주세요."
      - "레스토랑에서 주문할 때 특별 요청을 하는 상황을 연기해 주세요."`;
      break;
      
    case 7: // Part 6 PLUS: 질문하기 파트
      partSpecificPrompt = `이 파트는 주어진 상황에서 적절한 질문을 만드는 능력을 평가합니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 특정 정보를 얻기 위해 질문을 만들어야 하는 상황
      - 문제 해결을 위해 적절한 질문을 해야 하는 상황
      - 대화를 이끌어가기 위한 질문을 만들어야 하는 시나리오
      
      질문 예시:
      - "의사를 방문했습니다. 여러분의 건강 상태에 대해 의사에게 어떤 질문을 하시겠습니까?"
      - "새로운 도시로 이사했습니다. 이웃에게 지역 정보를 얻기 위해 어떤 질문을 하시겠습니까?"
      - "중고차를 구매하려고 합니다. 판매자에게 물어봐야 할 5가지 중요한 질문을 만들어보세요."`;
      break;
      
    case 8: // 스토리텔링 파트
      partSpecificPrompt = `이 파트는 주어진 주제나 상황을 바탕으로 창의적인 이야기를 만드는 능력을 평가합니다. 다음과 같은 유형의 질문을 만들어주세요:
      - 특정 상황이나 시작점을 주고 이야기를 만들도록 요청하는 질문
      - 특정 요소(인물, 장소, 사물)를 포함한 이야기를 만들도록 요청하는 질문
      - 과거 경험을 바탕으로 한 이야기를 만들도록 요청하는 질문
      
      질문 예시:
      - "길을 걷다가 의문의 편지를 발견했습니다. 이어지는 이야기를 만들어보세요."
      - "새로운 취미를 시작한 후 예상치 못한 일이 일어났습니다. 무슨 일이 있었는지 이야기해보세요."
      - "다음 세 단어(바다, 열쇠, 비밀)를 사용하여 짧은 이야기를 만들어보세요."`;
      break;
      
    default:
      partSpecificPrompt = `이 파트는 "${currentPart.description}"을 평가합니다. 자연스럽고 실제 시험과 같은 질문을 만들어주세요.`;
  }
  
  return partSpecificPrompt;
};

/**
 * 향상된 질문 생성 프롬프트 생성
 * @param {string} testType - 테스트 유형
 * @param {number} testPart - 현재 파트
 * @param {string} difficultyLevel - 난이도
 * @param {Array} questionTopics - 이미 사용된 주제들
 * @returns {string} 완성된 프롬프트
 */
export const getEnhancedQuestionPrompt = (testType, testPart, difficultyLevel, questionTopics) => {
  const currentTest = mockTestData[testType];
  const currentPart = currentTest.parts[testPart - 1];
  
  const allowedCategories = currentPart.categories || [];
  const previousQuestionTopics = [...questionTopics];
  const partSpecificPrompt = getPartSpecificPrompt(testType, testPart);
  
  let systemPrompt = '';
  let diversityCategoriesPrompt = `
파트에 적합한 카테고리:
${allowedCategories.map(cat => `- ${cat}`).join('\n')}

이미 질문한 카테고리/주제: ${previousQuestionTopics.join(', ') || '없음'}

절대로 이미 질문한 주제와 관련된 질문을 하지 마세요. 완전히 새로운 주제로 질문해야 합니다.
유사한 주제도 피해야 합니다. 예를 들어, '가족' 주제가 이미 나왔다면 '가족 여행', '부모님', '형제자매' 등과 같은 관련 주제도 피해야 합니다.
  `;
  
  switch(testType) {
    case 'japanese':
      systemPrompt = `あなたは日本語能力試験(SJPT)の面接官です。
Part ${testPart}: ${currentPart.name}のための質問を1つ作成してください。
このパートでは「${currentPart.description}」を評価します。

${partSpecificPrompt}

以前の質問と重複しないように、以下のカテゴリから新しい分野を選んでください:
${diversityCategoriesPrompt}

重要: 質問は${difficultyLevel}レベルの学習者向けに、シンプル、明確、短く(最大1-2の短い文)してください。
質問は日本語で作成してください。毎回異なる質問を作成し、日本語の試験で実際に出るような質問にしてください。`;
      break;

    case 'korean':
      systemPrompt = `당신은 한국어 능력 시험(TOPIK)의 면접관입니다.
파트 ${testPart}: ${currentPart.name}을 위한 질문을 하나 만들어주세요.
이 파트에서는 "${currentPart.description}"을 평가합니다.

${partSpecificPrompt}

이전 질문과 중복되지 않도록 다음 카테고리에서 새로운 영역을 선택해주세요:
${diversityCategoriesPrompt}

중요: 질문은 ${difficultyLevel} 수준의 학습자를 위해 간단하고, 명확하며, 짧게(최대 1-2개의 짧은 문장) 작성해주세요.
질문은 한국어로 작성해주세요. 매번 다른 질문을 만들고, 실제 한국어 시험에서 나올법한 질문으로 만들어주세요.`;
      break;
      
    case 'chinese':
      systemPrompt = `您是中国汉语水平考试(HSK)的考官。
请为第${testPart}部分：${currentPart.name}创建一个问题。
这部分测试"${currentPart.description}"。

${partSpecificPrompt}

为了避免与之前的问题重复，请从以下类别中选择一个新的领域:
${diversityCategoriesPrompt}

重要：问题必须面向${difficultyLevel}水平的学习者 - 保持简单、清晰和简短（最多1-2个短句）。
问题必须用中文。每次都要创建不同的问题，确保问题类似于真实的中文考试中会出现的问题。`;
      break;
      
    case 'englishExpress':
      systemPrompt = `You are an examiner for the OPIC English speaking test (Intermediate level).
Please generate a question for Part ${testPart}: ${currentPart.name}.
This part tests "${currentPart.description}".

${partSpecificPrompt}

To avoid overlap with previous questions, please select a new area from these categories:
${diversityCategoriesPrompt}

IMPORTANT: The question must be for ${difficultyLevel} level learners - keep it conversational, clear, and concise (max 1-2 short sentences).
Create different questions each time, similar to what would appear in a real OPIC test.`;
      break;
      
    case 'englishElite':
      systemPrompt = `You are an examiner for the OPIC English speaking test (Advanced/Superior level).
Please generate a question for Part ${testPart}: ${currentPart.name}.
This part tests "${currentPart.description}".

${partSpecificPrompt}

To avoid overlap with previous questions, please select a new area from these categories:
${diversityCategoriesPrompt}

IMPORTANT: The question must be for advanced level learners - make it thoughtful and nuanced, but still clear and concise (max 2 sentences).
Create different questions each time, similar to what would appear in a real high-level OPIC test.`;
      break;
      
    default:
      systemPrompt = `You are an examiner for the ${currentTest.name} test. 
Please generate a question for Part ${testPart}: ${currentPart.name}.
This part tests "${currentPart.description}".

${partSpecificPrompt}

To avoid overlap with previous questions, please select a new area from these categories:
${diversityCategoriesPrompt}

IMPORTANT: The question must be for ${difficultyLevel} level learners - keep it simple, clear, and SHORT (max 1-2 short sentences).
The question must be in ${languageData[currentTest.language]?.name || 'English'}.`;
  }
 
  return systemPrompt;
};

/**
 * 질문 생성 API 호출
 * @param {string} apiKey - OpenAI API 키
 * @param {string} testType - 테스트 유형
 * @param {number} testPart - 현재 파트
 * @param {string} difficultyLevel - 난이도
 * @param {Array} questionTopics - 사용된 주제들
 * @param {number} currentQuestionIndex - 현재 질문 인덱스
 * @returns {Promise<Object>} 질문 데이터
 */
export const generateQuestion = async (apiKey, testType, testPart, difficultyLevel, questionTopics, currentQuestionIndex) => {
  if (!apiKey) {
    throw new Error('API 키가 필요합니다.');
  }

  const currentTest = mockTestData[testType];
  const currentPart = currentTest.parts[testPart - 1];
  
  try {
    logInfo(`질문 생성 시작 - Part ${testPart}, Question ${currentQuestionIndex + 1}`);
    
    // 파트별 적합한 카테고리 사용
    const partCategories = currentPart.categories || [];
    const usedCategories = [...questionTopics];
    
    // 아직 사용되지 않은 파트 관련 카테고리 찾기
    const unusedCategories = partCategories.filter(cat => 
      !usedCategories.some(used => used.includes(cat))
    );
    
    // 사용할 카테고리 결정
    let targetCategory;
    if (unusedCategories.length > 0) {
      const randomIndex = Math.floor(Math.random() * unusedCategories.length);
      targetCategory = unusedCategories[randomIndex];
    } else {
      const randomIndex = Math.floor(Math.random() * partCategories.length);
      targetCategory = partCategories[randomIndex];
    }
    
    // 선택된 카테고리를 GPT 프롬프트에 명시적으로 지정
    const categoryInstruction = `
질문은 반드시 다음 카테고리에서 생성하세요: "${targetCategory}"
이전에 사용된 주제와는 완전히 다른 주제로 질문을 생성하세요.
이 파트의 특성(${currentPart.name}: ${currentPart.description})에 맞게 적절한 질문을 만들어주세요.`;
    
    // 파트별 특성이 반영된 향상된 시스템 프롬프트 가져오기
    const basePrompt = getEnhancedQuestionPrompt(testType, testPart, difficultyLevel, questionTopics);
    const systemPrompt = basePrompt + "\n\n" + categoryInstruction;
    
    // API 호출
    const response = await fetch('https://api.openai.com/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${apiKey}`
      },
      body: JSON.stringify({
        model: API_CONFIG.DEFAULT_MODEL,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: `Generate a diverse ${currentPart.name} test question for ${difficultyLevel} level in the category "${targetCategory}". The question must be different from previous ones and appropriate for ${currentPart.name}.` }
        ],
        max_tokens: 300,
        temperature: 0.8
      })
    });

    if (!response.ok) {
      throw new Error(`API 요청 실패: ${response.status}`);
    }

    const data = await response.json();
    let generatedQuestion = data.choices[0].message.content.trim();
    
    // 응답 정리
    generatedQuestion = generatedQuestion.replace(/^["'](.*)["']$/, '$1');
    generatedQuestion = generatedQuestion.replace(/^(질문:|Question:|问题:)\s*/i, '');
    
    logInfo('질문 생성 완료:', generatedQuestion);
    
    return {
      id: Date.now(),
      part: testPart,
      partName: currentPart.name,
      text: generatedQuestion,
      category: targetCategory,
      difficulty: difficultyLevel,
      answerTime: currentPart.answerTime
    };
    
  } catch (error) {
    logInfo('질문 생성 오류:', error);
    throw error;
  }
};

/**
 * 질문 유효성 검사
 * @param {Object} question - 질문 객체
 * @returns {boolean} 유효 여부
 */
export const validateQuestion = (question) => {
  if (!question || typeof question !== 'object') return false;
  if (!question.text || question.text.trim().length === 0) return false;
  if (!question.part || question.part < 1) return false;
  if (!question.partName || question.partName.trim().length === 0) return false;
  
  return true;
};

/**
 * 질문 중복 확인
 * @param {string} newQuestion - 새로운 질문
 * @param {Array} existingQuestions - 기존 질문들
 * @returns {boolean} 중복 여부
 */
export const isDuplicateQuestion = (newQuestion, existingQuestions) => {
  if (!newQuestion || !Array.isArray(existingQuestions)) return false;
  
  const normalizedNew = newQuestion.toLowerCase().trim();
  
  return existingQuestions.some(q => {
    const normalizedExisting = q.text.toLowerCase().trim();
    return normalizedNew === normalizedExisting || 
           normalizedNew.includes(normalizedExisting) ||
           normalizedExisting.includes(normalizedNew);
  });
};

/**
 * 질문 난이도 조정
 * @param {string} question - 원본 질문
 * @param {string} currentDifficulty - 현재 난이도
 * @param {string} targetDifficulty - 목표 난이도
 * @returns {string} 조정된 질문
 */
export const adjustQuestionDifficulty = (question, currentDifficulty, targetDifficulty) => {
  if (currentDifficulty === targetDifficulty) return question;
  
  // 난이도 조정 로직은 추후 AI 모델을 통해 구현 가능
  // 현재는 원본 질문 반환
  return question;
};

/**
 * 질문 통계 정보 가져오기
 * @param {Array} questions - 질문 배열
 * @returns {Object} 통계 정보
 */
export const getQuestionStats = (questions) => {
  if (!Array.isArray(questions) || questions.length === 0) {
    return {
      total: 0,
      byPart: {},
      byCategory: {},
      averageLength: 0
    };
  }
  
  const stats = {
    total: questions.length,
    byPart: {},
    byCategory: {},
    averageLength: 0
  };
  
  let totalLength = 0;
  
  questions.forEach(q => {
    // 파트별 통계
    if (!stats.byPart[q.part]) {
      stats.byPart[q.part] = 0;
    }
    stats.byPart[q.part]++;
    
    // 카테고리별 통계
    if (q.category) {
      if (!stats.byCategory[q.category]) {
        stats.byCategory[q.category] = 0;
      }
      stats.byCategory[q.category]++;
    }
    
    // 길이 통계
    totalLength += q.text.length;
  });
  
  stats.averageLength = Math.round(totalLength / questions.length);
  
  return stats;
};

/**
 * 다음 추천 카테고리 가져오기
 * @param {string} testType - 테스트 유형
 * @param {number} testPart - 현재 파트
 * @param {Array} usedCategories - 사용된 카테고리들
 * @returns {string} 추천 카테고리
 */
export const getRecommendedCategory = (testType, testPart, usedCategories) => {
  const currentTest = mockTestData[testType];
  const currentPart = currentTest.parts[testPart - 1];
  const availableCategories = currentPart.categories || [];
  
  const unusedCategories = availableCategories.filter(cat => 
    !usedCategories.includes(cat)
  );
  
  if (unusedCategories.length > 0) {
    return unusedCategories[Math.floor(Math.random() * unusedCategories.length)];
  }
  
  return availableCategories[Math.floor(Math.random() * availableCategories.length)];
};

export default {
  getPartSpecificPrompt,
  getEnhancedQuestionPrompt,
  generateQuestion,
  validateQuestion,
  isDuplicateQuestion,
  adjustQuestionDifficulty,
  getQuestionStats,
  getRecommendedCategory
};