// 카테고리 관련 헬퍼 함수들
export const getCategoryDescription = (categoryName) => {
 return detailedCategories[categoryName]?.description || categoryName;
};

export const getCategoryKeywords = (categoryName) => {
 return detailedCategories[categoryName]?.keywords || [];
};

export const getRandomCategoryFromPart = (testType, partNumber) => {
 const part = mockTestData[testType]?.parts[partNumber - 1];
 if (!part || !part.categories || part.categories.length === 0) {
   return null;
 }
 
 const randomIndex = Math.floor(Math.random() * part.categories.length);
 return part.categories[randomIndex];
};

export const getUnusedCategories = (testType, partNumber, usedCategories) => {
 const part = mockTestData[testType]?.parts[partNumber - 1];
 if (!part || !part.categories) {
   return [];
 }
 
 return part.categories.filter(category => !usedCategories.includes(category));
};

// 전체 질문 수 계산 함수
export const getTotalQuestions = (testType) => {
 return mockTestData[testType]?.parts.reduce((total, part) => total + part.questions, 0) || 0;
};

// 현재 질문 번호 계산 함수
export const getCurrentQuestionNumber = (testType, currentPart, currentQuestionIndex) => {
 const parts = mockTestData[testType]?.parts || [];
 let questionNumber = 0;
 
 // 이전 파트들의 질문 수 합계
 for (let i = 0; i < currentPart - 1; i++) {
   questionNumber += parts[i]?.questions || 0;
 }
 
 // 현재 파트의 현재 질문 인덱스 추가
 questionNumber += currentQuestionIndex + 1;
 
 return questionNumber;
};

// 진행률 계산 함수
export const getProgressPercentage = (testType, currentPart, currentQuestionIndex) => {
 const totalQuestions = getTotalQuestions(testType);
 const currentQuestionNumber = getCurrentQuestionNumber(testType, currentPart, currentQuestionIndex);
 
 return totalQuestions > 0 ? Math.round((currentQuestionNumber / totalQuestions) * 100) : 0;
};

// 파트 그룹 정보 가져오기
export const getPartGroupInfo = (partNumber) => {
 return partGroups.find(group => group.parts.includes(partNumber));
};

// 유효성 검사 함수들
export const isValidTestType = (testType) => {
 return testType && mockTestData[testType];
};

export const isValidPartNumber = (testType, partNumber) => {
 if (!isValidTestType(testType)) return false;
 const parts = mockTestData[testType].parts;
 return partNumber >= 1 && partNumber <= parts.length;
};

export const isValidLanguage = (language) => {
 return language && languageData[language];
};

// 카테고리 통계 함수
export const getCategoryStats = (testType) => {
 const test = mockTestData[testType];
 if (!test) return {};
 
 const categoryCount = {};
 const categoryByPart = {};
 
 test.parts.forEach((part, index) => {
   const partNum = index + 1;
   categoryByPart[partNum] = part.categories.length;
   
   part.categories.forEach(category => {
     categoryCount[category] = (categoryCount[category] || 0) + 1;
   });
 });
 
 return {
   totalCategories: Object.keys(categoryCount).length,
   categoryCount,
   categoryByPart,
   mostUsedCategory: Object.keys(categoryCount).reduce((a, b) => 
     categoryCount[a] > categoryCount[b] ? a : b
   )
 };
};

// 카테고리 다양성 체크 함수
export const checkCategoryDiversity = (usedCategories, testType, partNumber) => {
 const part = mockTestData[testType]?.parts[partNumber - 1];
 if (!part) return { diversity: 0, recommendation: null };
 
 const totalCategories = part.categories.length;
 const usedCount = usedCategories.length;
 const diversity = Math.round((usedCount / totalCategories) * 100);
 
 const unusedCategories = part.categories.filter(cat => !usedCategories.includes(cat));
 const recommendation = unusedCategories.length > 0 ? 
   unusedCategories[Math.floor(Math.random() * unusedCategories.length)] : null;
 
 return {
   diversity,
   recommendation,
   totalCategories,
   usedCount,
   unusedCount: unusedCategories.length
 };
};

// 디바이스 감지 유틸리티
export const getDeviceInfo = () => {
 const userAgent = navigator.userAgent;
 return {
   isAndroid: /Android/i.test(userAgent),
   isIOS: /iPad|iPhone|iPod/.test(userAgent) && !window.MSStream,
   isMobile: /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(userAgent),
   isChrome: /Chrome/i.test(userAgent),
   isSafari: /Safari/i.test(userAgent) && !/Chrome/i.test(userAgent)
 };
};

