// 개인화된 학습 리포트 생성
export const generatePersonalizedReport = (session, metrics, badges) => {
 const strengths = [];
 const improvements = [];
 const recommendations = [];
 
 // 강점 분석
 if (metrics.averageScore >= 85) {
   strengths.push('전반적으로 우수한 언어 실력을 보여주고 있습니다.');
 }
 if (metrics.averageResponseTime <= 45) {
   strengths.push('빠른 응답 속도로 유창성이 뛰어납니다.');
 }
 if (session.usedCategories.length >= 10) {
   strengths.push('다양한 주제에 대해 균형 잡힌 표현 능력을 갖추고 있습니다.');
 }
 
 // 개선점 분석
 if (metrics.averageScore < 75) {
   improvements.push('전반적인 언어 정확성 향상이 필요합니다.');
   recommendations.push('기본 문법과 어휘 학습에 더 집중해보세요.');
 }
 if (metrics.averageResponseTime > 60) {
   improvements.push('응답 속도를 높여 더 자연스러운 대화가 가능하도록 연습이 필요합니다.');
   recommendations.push('일상 대화 연습을 통해 유창성을 기르세요.');
 }
 
 // 맞춤형 추천
 const learningPath = generateLearningPath(session.testType, session.difficultyLevel, improvements);
 
 return {
   sessionInfo: {
     testType: session.testType,
     userName: session.userName,
     difficultyLevel: session.difficultyLevel,
     completedAt: new Date().toISOString()
   },
   performance: metrics,
   achievements: badges,
   analysis: {
     strengths,
     improvements,
     recommendations
   },
   learningPath,
   nextSteps: [
     '약점 영역에 대한 집중 학습 계획 수립',
     '정기적인 모의 테스트를 통한 실력 확인',
     '다양한 주제의 실제 대화 경험 늘리기'
   ]
 };
};

// 데이터 내보내기 함수
export const exportTestData = (session, format = 'json') => {
 const exportData = {
   ...session,
   exportedAt: new Date().toISOString(),
   version: '1.0'
 };
 
 switch (format) {
   case 'json':
     return JSON.stringify(exportData, null, 2);
   case 'csv':
     // CSV 형태로 변환하는 로직
     const headers = ['질문번호', '파트', '카테고리', '응답시간', '점수'];
     const rows = session.responses.map((response, index) => [
       index + 1,
       response.part || '',
       response.category || '',
       response.duration || 0,
       response.score || 0
     ]);
     return [headers, ...rows].map(row => row.join(',')).join('\n');
   default:
     return JSON.stringify(exportData);
 }
};

// 로컬 스토리지 관리
export const saveToLocalStorage = (key, data) => {
 try {
   localStorage.setItem(key, JSON.stringify(data));
   return true;
 } catch (error) {
   logInfo('로컬 스토리지 저장 실패:', error);
   return false;
 }
};

export const loadFromLocalStorage = (key, defaultValue = null) => {
 try {
   const data = localStorage.getItem(key);
   return data ? JSON.parse(data) : defaultValue;
 } catch (error) {
   logInfo('로컬 스토리지 로드 실패:', error);
   return defaultValue;
 }
};

export const clearLocalStorage = (key) => {
 try {
   if (key) {
     localStorage.removeItem(key);
   } else {
     // 모든 OpenVoiceAI 관련 데이터 삭제
     Object.values(STORAGE_KEYS).forEach(storageKey => {
       localStorage.removeItem(storageKey);
     });
   }
   return true;
 } catch (error) {
   logInfo('로컬 스토리지 삭제 실패:', error);
   return false;
 }
};