import React, { useState, useEffect, useRef, useCallback } from 'react';
import './TutorMode.css';

const TutorFreeMode = ({ apiKey, selectedLanguage, level }) => {
  // 기존 상태
  const [messages, setMessages] = useState([]);
  const [inputText, setInputText] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [topics, setTopics] = useState([]);
  const [selectedTopic, setSelectedTopic] = useState(null);
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [detectedLanguage, setDetectedLanguage] = useState(selectedLanguage);
  
  // 커스텀 주제 관련 상태 추가
  const [customTopicInput, setCustomTopicInput] = useState('');
  const [showCustomTopicInput, setShowCustomTopicInput] = useState(false);
  
  // 피드백 관련 상태 추가
  const [feedbackRequested, setFeedbackRequested] = useState(false);
  const [feedbackLanguage, setFeedbackLanguage] = useState('korean'); // 기본 피드백 언어
  const [feedbackForMessage, setFeedbackForMessage] = useState(null); // 피드백을 요청한 메시지
  const [feedbackText, setFeedbackText] = useState('');
  const [isFeedbackLoading, setIsFeedbackLoading] = useState(false);
  
  const chatContainerRef = useRef(null);
  const recognitionRef = useRef(null);
  const autoScrollRef = useRef(true);
  const lockRef = useRef(false);
  
  // 언어 이름 매핑 - App.js와 일치하도록 수정
  const languageNames = {
    'englishexpress': 'English',
    'englishelite': 'English', 
    'japanese': '日本語',
    'korean': '한국어',
    'chinese': '中文',
    'spanish': 'Español',
    'french': 'Français',
    'german': 'Deutsch',
    'russian': 'Русский',
    'arabic': 'العربية',
    'vietnamese': 'Tiếng Việt',
    'thai': 'ไทย',
    'indonesian': 'Bahasa Indonesia'
  };
  
  // 언어 코드 매핑 (음성 인식용) - App.js와 일치하도록 수정
  const languageCodes = {
    'englishexpress': 'en-US',
    'englishelite': 'en-CA',
    'japanese': 'ja-JP',
    'korean': 'ko-KR',
    'chinese': 'zh-CN',
    'spanish': 'es-ES',
    'french': 'fr-FR',
    'german': 'de-DE',
    'russian': 'ru-RU',
    'arabic': 'ar-SA',
    'vietnamese': 'vi-VN',
    'thai': 'th-TH',
    'indonesian': 'id-ID'
  };

  // 컴포넌트 마운트 시 기본 주제 로드
  useEffect(() => {
    loadDefaultTopics();
    setupSpeechRecognition();
    
    // 첫 인사 메시지 추가
    const greeting = getGreetingMessage();
    setMessages([
      { 
        role: 'assistant', 
        content: greeting,
        timestamp: new Date().toISOString()
      }
    ]);
    
    // 음성 합성 초기화 및 인사말 음성으로 재생
    setTimeout(() => {
      speakText(greeting);
    }, 500);
    
    return () => {
      // 컴포넌트 언마운트 시 리소스 정리
      cleanupResources();
    };
  }, [selectedLanguage]);
  
  // 리소스 정리 함수
  const cleanupResources = useCallback(() => {
    // 음성 인식 중지
    if (recognitionRef.current) {
      try {
        recognitionRef.current.stop();
      } catch (error) {
        console.error('음성 인식 정리 오류:', error);
      }
      recognitionRef.current.onresult = null;
      recognitionRef.current.onend = null;
      recognitionRef.current.onerror = null;
    }
    
    // 음성 합성 중지
    if (window.speechSynthesis) {
      window.speechSynthesis.cancel();
    }
    
    // 잠금 해제
    lockRef.current = false;
  }, []);
  
  // 채팅이 업데이트될 때마다 스크롤 아래로 이동 (자동 스크롤)
  useEffect(() => {
    if (chatContainerRef.current && autoScrollRef.current) {
      chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
    }
  }, [messages]);
  
  // 인사말 메시지 생성 - 영어 지원 강화
  const getGreetingMessage = () => {
    const languageName = languageNames[selectedLanguage] || 'English';
    
    switch(selectedLanguage) {
      case 'englishexpress':
      case 'englishelite':
        return `Hi there! I'm your AI language tutor for ${languageName}. How can I help you practice today?`;
      case 'korean':
        return `안녕하세요! 저는 ${languageName} 학습을 도와드릴 AI 튜터입니다. 오늘은 어떤 대화를 연습하고 싶으신가요?`;
      case 'japanese':
        return `こんにちは！私はあなたの${languageName}のAI言語チューターです。今日はどのように練習をお手伝いできますか？`;
      case 'chinese':  // ✅ 중국어 케이스 추가
        return `你好！我是你的${languageName}AI语言导师。今天我可以怎样帮助你练习中文呢？`;
      default:
        return `Hello! I'm your AI language tutor for ${languageName}. Let's practice together!`;
    }
  };
  
  // 기본 주제 로드
  const loadDefaultTopics = () => {
    const defaultTopics = [
      { id: 'daily', name: '일상 대화', icon: '🏠', description: '일상적인 주제로 대화해요' },
      { id: 'travel', name: '여행', icon: '✈️', description: '여행 경험과 계획에 대해 이야기해요' },
      { id: 'food', name: '음식', icon: '🍕', description: '음식 취향과 요리에 대해 대화해요' },
      { id: 'hobby', name: '취미', icon: '🎨', description: '다양한 취미 활동에 대해 이야기해요' },
      { id: 'culture', name: '문화', icon: '🏛️', description: '문화적 차이와 경험에 대해 대화해요' },
      { id: 'work', name: '직장/학교', icon: '💼', description: '일과 학교생활에 대해 이야기해요' },
      { id: 'technology', name: '기술/IT', icon: '💻', description: 'IT와 기술에 대해 대화해요' },
      { id: 'health', name: '건강/의료', icon: '🏥', description: '건강 관리와 의료에 대해 이야기해요' },
      { id: 'sports', name: '스포츠', icon: '⚽', description: '스포츠와 운동에 대해 대화해요' },
      { id: 'entertainment', name: '엔터테인먼트', icon: '🎬', description: '영화, TV, 공연에 대해 이야기해요' },
      { id: 'music', name: '음악', icon: '🎵', description: '음악 취향과 경험에 대해 대화해요' },
      { id: 'art', name: '미술/디자인', icon: '🖼️', description: '미술과 디자인에 대해 이야기해요' },
      { id: 'science', name: '과학', icon: '🔬', description: '과학적 주제에 대해 대화해요' },
      { id: 'environment', name: '환경', icon: '🌱', description: '환경 보호와 지속가능성에 대해 이야기해요' },
      { id: 'news', name: '뉴스/시사', icon: '📰', description: '최근 뉴스와 시사에 대해 대화해요' },
      { id: 'shopping', name: '쇼핑', icon: '🛍️', description: '쇼핑 경험과 선호도에 대해 이야기해요' },
      { id: 'family', name: '가족', icon: '👪', description: '가족과 관련된 주제로 대화해요' },
      { id: 'relationships', name: '인간관계', icon: '💑', description: '친구와 인간관계에 대해 이야기해요' }
    ];
    
    setTopics(defaultTopics);
  };
  
  // 주제 선택 처리
  const handleTopicSelect = (topic) => {
    setSelectedTopic(topic);
    
    // 선택된 주제에 대한 메시지 추가
    const topicMessage = topic.name === '자유 대화' 
      ? '자유롭게 대화해 보세요' 
      : `${topic.name} 주제로 대화해 보세요`;
      
    const userMessage = {
      role: 'user',
      content: `${topicMessage}`,
      timestamp: new Date().toISOString()
    };
    
    setMessages(prev => [...prev, userMessage]);
    
    // 자동 스크롤 활성화
    autoScrollRef.current = true;
    
    // AI 응답 생성
    generateTutorResponse(userMessage.content, true);
  };
  
  // 커스텀 주제 제출 처리
  const handleCustomTopicSubmit = () => {
    if (!customTopicInput.trim()) return;
    
    const customTopic = {
      id: 'custom-' + Date.now(),
      name: customTopicInput,
      icon: '💬',
      description: '직접 입력한 주제로 대화해요',
      isCustom: true
    };
    
    setSelectedTopic(customTopic);
    
    // 선택된 주제에 대한 메시지 추가
    const userMessage = {
      role: 'user',
      content: `${customTopic.name} 주제로 대화해 보고 싶어요`,
      timestamp: new Date().toISOString()
    };
    
    setMessages(prev => [...prev, userMessage]);
    
    // 자동 스크롤 활성화
    autoScrollRef.current = true;
    
    // AI 응답 생성
    generateTutorResponse(userMessage.content, true);
    
    // 입력 필드 및 모달 초기화
    setCustomTopicInput('');
    setShowCustomTopicInput(false);
  };
  
  // 개선된 언어 감지 함수 - 영어 감지 강화
  const detectLanguage = useCallback((text) => {
    if (!text || text.trim() === '') return selectedLanguage;
    
    // 한국어 패턴
    const koreanPattern = /[ㄱ-ㅎ|ㅏ-ㅣ|가-힣]/;
    if (koreanPattern.test(text)) {
      return 'korean';
    }
    
    // 일본어 패턴
    if (/[\u3040-\u309F\u30A0-\u30FF]/.test(text)) return 'japanese';
    
    // 중국어 패턴
    if (/[\u4E00-\u9FFF]/.test(text)) return 'chinese';
    
    // 영어 패턴 강화 - 영어 알파벳만 있고 다른 언어 문자가 없으면 영어로 판단
    const englishPattern = /^[a-zA-Z\s\.,!?'"0-9\-]+$/;
    if (englishPattern.test(text.trim())) {
      // 영어 학습 모드인 경우 영어로 감지
      if (selectedLanguage === 'englishexpress' || selectedLanguage === 'englishelite') {
        return selectedLanguage;
      }
      return 'englishexpress'; // 기본 영어
    }
    
    // 기본값: 학습 언어
    return selectedLanguage;
  }, [selectedLanguage]);
  
  // AI 튜터 응답 생성 (GPT-4 Turbo + Stream 활용) - 영어 지원 강화
  const generateTutorResponse = async (userMessage, isTopicSelection = false) => {
    if (!apiKey) {
      alert('API 키가 필요합니다.');
      return;
    }
    
    // 이미 처리 중이면 중단
    if (lockRef.current) {
      console.log('이미 응답 생성 중입니다.');
      return;
    }
    
    // 처리 중 상태 및 잠금 설정
    setIsTyping(true);
    lockRef.current = true;
    
    try {
      // 언어 감지
      const messageLanguage = detectLanguage(userMessage);
      setDetectedLanguage(messageLanguage);
      
      const languageName = languageNames[selectedLanguage] || 'English';
      const languageLevel = level || 'beginner';
      
      // 영어별 시스템 프롬프트 개선
      let systemPrompt;
      
      if (selectedLanguage === 'englishexpress' || selectedLanguage === 'englishelite') {
        // 영어 학습 모드
        systemPrompt = `
You are a friendly and helpful English language tutor. 
The learner's level is ${languageLevel}.
Please follow these guidelines:

1. Help the learner practice English through natural conversation.
2. Adjust the conversation difficulty to match the learner's skill level.
3. Speak in a natural and friendly tone, like a friend or colleague.
4. Use short and concise sentences.
5. If the learner makes errors, don't correct them immediately - continue the conversation naturally.
6. Always include appropriate follow-up questions to keep the conversation flowing.
7. Respond entirely in English, but you may include simple explanations in Korean if necessary for beginners.
8. When introducing new words or expressions, provide simple example sentences.

Always respond in English and maintain a natural conversation flow.
The current selected topic is "${selectedTopic?.name || 'Free conversation'}".
        `;
      } else {
        // 다른 언어 학습 모드
        systemPrompt = `
당신은 친절하고 도움이 되는 ${languageName} 언어 튜터입니다. 
학습자의 레벨은 ${languageLevel}입니다.
다음 가이드라인을 따라주세요:

1. 학습자와 자연스럽게 대화하며 ${languageName}를 연습할 수 있게 도와주세요.
2. 학습자의 언어 실력에 맞게 대화 난이도를 조절해주세요.
3. 자연스럽고 친근한 톤으로 대화하세요. 친구나 동료처럼 편안하게 대화해주세요.
4. 짧고 간결한 문장을 사용하세요.
5. 학습자의 오류가 있더라도 즉시 수정하지 말고 자연스럽게 대화를 이어가세요.
6. 대화가 끊기지 않도록 적절한 후속 질문을 항상 포함해주세요.
7. 모든 응답은 ${languageName}로 작성하되, 필요시 학습자의 모국어로 간단한 설명을 포함할 수 있습니다.
8. 새로운 단어나 표현을 소개할 때는 간단한 예문을 함께 제공해주세요.

응답은 항상 ${languageName}로 작성하고, 자연스러운 대화 흐름을 유지하세요.
현재 선택된 주제는 "${selectedTopic?.name || '자유 대화'}" 입니다.
        `;
      }
      
      // 대화 컨텍스트 구성 (최근 10개 메시지만 사용하여 컨텍스트 제한)
      const conversationHistory = messages
        .slice(-10)
        .map(msg => ({
          role: msg.role,
          content: msg.content
        }));
      
      // 임시 메시지 ID 생성
      const tempMessageId = Date.now().toString();
      
      // 응답 스트리밍을 위한 빈 메시지 추가
      setMessages(prev => [...prev, { 
        id: tempMessageId,
        role: 'assistant', 
        content: '', 
        isTyping: true,
        timestamp: new Date().toISOString() 
      }]);
      
      // 자동 스크롤 활성화
      autoScrollRef.current = true;
      
      // OpenAI API 호출 (스트리밍)
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo',
          messages: [
            { role: 'system', content: systemPrompt },
            ...conversationHistory,
            { role: 'user', content: userMessage }
          ],
          temperature: 0.7,
          stream: true
        })
      });
      
      if (!response.ok) {
        throw new Error(`API 요청 실패: ${response.status}`);
      }
      
      // 스트림 읽기
      const reader = response.body.getReader();
      const decoder = new TextDecoder('utf-8');
      let fullContent = '';
      let hasStartedDisplaying = false;
      
      while (true) {
        const { done, value } = await reader.read();
        if (done) {
          break;
        }
        
        // 청크 디코딩
        const chunk = decoder.decode(value, { stream: true });
        
        // 이벤트 데이터 파싱
        const lines = chunk.split('\n');
        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const data = line.substring(6);
            if (data === '[DONE]') {
              continue;
            }
            
            try {
              const parsedData = JSON.parse(data);
              if (parsedData.choices && 
                  parsedData.choices[0] && 
                  parsedData.choices[0].delta && 
                  parsedData.choices[0].delta.content) {
                
                fullContent += parsedData.choices[0].delta.content;
                
                // 최초 내용이 도착하면 음성 합성 시작 (선택적)
                if (!hasStartedDisplaying && fullContent.trim().length > 10) {
                  hasStartedDisplaying = true;
                }
                
                // 메시지 업데이트 (타이핑 효과)
                setMessages(prev => prev.map(msg => 
                  msg.id === tempMessageId 
                    ? { ...msg, content: fullContent } 
                    : msg
                ));
                
                // 적절한 타이핑 속도 조절
                await new Promise(resolve => setTimeout(resolve, 20));
              }
            } catch (err) {
              console.error('JSON 파싱 오류:', err);
            }
          }
        }
      }
      
      // 스트리밍 완료 후 메시지 최종 업데이트
      setMessages(prev => prev.map(msg => 
        msg.id === tempMessageId 
          ? { ...msg, content: fullContent, isTyping: false, completed: true } 
          : msg
      ));
      
      // 응답 음성으로 재생
      speakText(fullContent);
      
    } catch (error) {
      console.error('튜터 응답 생성 오류:', error);
      alert(`응답 생성 중 오류가 발생했습니다: ${error.message}`);
    } finally {
      setIsTyping(false);
      // 잠금 해제
      lockRef.current = false;
    }
  };
  
  // 음성 인식 설정
  const setupSpeechRecognition = () => {
    // Web Speech API 지원 확인
    if (!('webkitSpeechRecognition' in window) && !('SpeechRecognition' in window)) {
      console.warn('이 브라우저는 음성 인식을 지원하지 않습니다.');
      return;
    }
    
    // SpeechRecognition 객체 생성
    const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
    recognitionRef.current = new SpeechRecognition();
    
    // 설정
    recognitionRef.current.continuous = true;
    recognitionRef.current.interimResults = true;
    recognitionRef.current.lang = languageCodes[selectedLanguage] || 'en-US';
    
    // 이벤트 핸들러
    recognitionRef.current.onresult = (event) => {
      const transcript = Array.from(event.results)
        .map(result => result[0].transcript)
        .join('');
      
      setInputText(transcript);
      
      // 언어 감지
      if (transcript.trim() !== '') {
        const detectedLang = detectLanguage(transcript);
        setDetectedLanguage(detectedLang);
      }
    };
    
    recognitionRef.current.onend = () => {
      setIsListening(false);
    };
    
    recognitionRef.current.onerror = (event) => {
      console.error('음성 인식 오류:', event.error);
      setIsListening(false);
    };
  };
  
  // 음성 인식 시작/중지
  const toggleSpeechRecognition = () => {
    if (!recognitionRef.current) {
      setupSpeechRecognition();
    }
    
    if (isListening) {
      try {
        recognitionRef.current.stop();
        setIsListening(false);
      } catch (error) {
        console.error('음성 인식 중지 오류:', error);
      }
    } else {
      // 입력창 비우기
      setInputText('');
      
      try {
        recognitionRef.current.start();
        setIsListening(true);
      } catch (error) {
        console.error('음성 인식 시작 오류:', error);
      }
    }
  };
  
  // 텍스트를 음성으로 변환
  const speakText = (text) => {
    // Web Speech API 지원 확인
    if (!('speechSynthesis' in window)) {
      console.warn('이 브라우저는 음성 합성을 지원하지 않습니다.');
      return;
    }
    
    // 기존 음성 완전히 정지
    if (window.speechSynthesis.speaking || isSpeaking) {
      window.speechSynthesis.cancel();
    }
    
    // 짧은 지연 후 새 음성 시작 (interrupted 에러 방지)
    setTimeout(() => {
      // 음성 합성 설정
      const utterance = new SpeechSynthesisUtterance(text);
      utterance.lang = languageCodes[selectedLanguage] || 'en-US';
      utterance.rate = 0.95; // 약간 느린 속도
      utterance.pitch = 1.0;
      
      // 구글 크롬의 고품질 중국어 음성 우선 선택
      const voices = window.speechSynthesis.getVoices();
      console.log('사용 가능한 모든 음성:', voices.map(v => `${v.name} (${v.lang})`));
      
      const languagePrefix = utterance.lang.split('-')[0];
      const languageVoices = voices.filter(voice => 
        voice.lang.startsWith(languagePrefix)
      );
      
      if (languageVoices.length > 0) {
        // 중국어는 구글 크롬 음성 우선 선택
        if (selectedLanguage === 'chinese') {
          const googleChineseVoice = languageVoices.find(voice => 
            voice.name.includes('Google') ||
            voice.name.includes('Chrome') ||
            voice.name.includes('Mandarin') ||
            voice.name.includes('Chinese')
          );
          
          if (googleChineseVoice) {
            utterance.voice = googleChineseVoice;
            console.log('✅ 구글 중국어 음성 선택:', googleChineseVoice.name);
          } else {
            // 구글이 없으면 고품질 음성 찾기
            const goodChineseVoice = languageVoices.find(voice => 
              voice.name.includes('Microsoft') || 
              voice.name.includes('Premium') ||
              voice.name.includes('Enhanced') ||
              voice.name.includes('Neural')
            );
            utterance.voice = goodChineseVoice || languageVoices[0];
            console.log('✅ 대체 중국어 음성 선택:', utterance.voice.name);
          }
        } else {
          utterance.voice = languageVoices[0];
        }
      }
      
      // 이벤트 핸들러 (에러 처리 개선)
      utterance.onstart = () => {
        setIsSpeaking(true);
      };
      
      utterance.onend = () => {
        setIsSpeaking(false);
      };
      
      utterance.onerror = (event) => {
        console.log('음성 에러 (무시):', event.error);
        setIsSpeaking(false);
      };
      
      // 음성 재생
      window.speechSynthesis.speak(utterance);
    }, 50);
  };
  
  // 음성 설정
// 음성 설정
const setVoice = (utterance) => {
  const voices = window.speechSynthesis.getVoices();
  const languagePrefix = languageCodes[selectedLanguage].split('-')[0];
  const languageVoices = voices.filter(voice => 
    voice.lang.startsWith(languagePrefix)
  );
  
  if (languageVoices.length > 0) {
    // 프락티스 모드와 동일하게 단순화 - 첫 번째 매칭 음성 사용
    utterance.voice = languageVoices[0];
  }
};
  
  // 피드백 요청 함수 (새로 추가)
  const requestFeedback = (message) => {
    if (!message || message.role !== 'user') return;
    
    setFeedbackForMessage(message);
    setFeedbackRequested(true);
    setFeedbackText('');
  };
  
  // 피드백 취소 함수 (새로 추가)
  const cancelFeedback = () => {
    setFeedbackRequested(false);
    setFeedbackForMessage(null);
    setFeedbackText('');
  };
  
  // 피드백 생성 함수 (기존 함수 수정)
  const generateLanguageFeedback = async () => {
    if (!apiKey || !feedbackForMessage) {
      return;
    }
    
    setIsFeedbackLoading(true);
    
    try {
      const languageName = languageNames[selectedLanguage] || 'English';
      const userMessage = feedbackForMessage.content;
      
      // 피드백을 위한 프롬프트
      const feedbackPrompt = `
학습자가 ${languageName} 학습 중 다음과 같이 말했습니다:

"${userMessage}"

학습자가 선택한 피드백 언어는 ${languageNames[feedbackLanguage]}입니다.
${feedbackLanguage}로 다음 형식의 피드백을 제공해주세요:

1. 좋았던 점: (잘 사용한 표현, 문법, 단어 등)
2. 개선할 점: (오류가 있는 부분 또는 더 자연스러운 표현 방식)
3. 대안 표현: (같은 의미를 더 자연스럽게 표현하는 방법)
4. 유용한 추가 표현: (관련 상황에서 사용할 수 있는 다른 유용한 표현들)

피드백은 건설적이고 격려하는 톤으로 작성해주세요. ${feedbackLanguage}로 응답해주세요.
      `;
      
      // OpenAI API 호출
      const response = await fetch('https://api.openai.com/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: 'gpt-4-turbo',
          messages: [
            { role: 'system', content: '당신은 언어 학습 피드백 전문가입니다.' },
            { role: 'user', content: feedbackPrompt }
          ],
          temperature: 0.7,
          max_tokens: 500
        })
      });
      
      if (!response.ok) {
        throw new Error(`피드백 API 요청 실패: ${response.status}`);
      }
      
      const data = await response.json();
      const feedbackContent = data.choices[0].message.content;
      
      // 피드백 설정
      setFeedbackText(feedbackContent);
      
    } catch (error) {
      console.error('피드백 생성 오류:', error);
      setFeedbackText('피드백을 생성하는 중 오류가 발생했습니다.');
    } finally {
      setIsFeedbackLoading(false);
    }
  };
  
  // 피드백 언어 변경 핸들러 (새로 추가)
  const handleFeedbackLanguageChange = (e) => {
    setFeedbackLanguage(e.target.value);
    
    // 이미 피드백이 표시중이면 새 언어로 다시 생성
    if (feedbackText && feedbackForMessage) {
      generateLanguageFeedback();
    }
  };
  
  // 스크롤 이벤트 핸들러 (자동 스크롤 제어)
  const handleScroll = () => {
    if (chatContainerRef.current) {
      const { scrollTop, scrollHeight, clientHeight } = chatContainerRef.current;
      const isAtBottom = scrollHeight - scrollTop - clientHeight < 20;
      
      // 바닥에 있으면 자동 스크롤 활성화, 아니면 비활성화
      autoScrollRef.current = isAtBottom;
    }
  };
  
  // 메시지 전송 핸들러
  const handleSendMessage = () => {
    if (!inputText.trim() || lockRef.current) return;
    
    // 사용자 메시지 추가
    const userMessage = {
      role: 'user',
      content: inputText,
      timestamp: new Date().toISOString()
    };
    
    setMessages(prev => [...prev, userMessage]);
    
    // 입력 필드 초기화
    setInputText('');
    
    // 자동 스크롤 활성화
    autoScrollRef.current = true;
    
    // 음성 인식 중지
    if (isListening) {
      if (recognitionRef.current) {
        try {
          recognitionRef.current.stop();
        } catch (error) {
          console.error('음성 인식 중지 오류:', error);
        }
      }
      setIsListening(false);
    }
    // AI 응답 생성
    generateTutorResponse(inputText);
  };
  
  // 키보드 입력 핸들러
  const handleKeyDown = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      
      if (showCustomTopicInput) {
        handleCustomTopicSubmit();
      } else {
        handleSendMessage();
      }
    }
  };
  
  // 주제 변경 핸들러
  const handleChangeTopic = () => {
    // 시스템 메시지 추가
    const systemMessage = {
      role: 'system',
      content: '주제를 변경합니다.',
      timestamp: new Date().toISOString()
    };
    
    setMessages(prev => [...prev, systemMessage]);
    setSelectedTopic(null);
    
    // 자동 스크롤 활성화
    autoScrollRef.current = true;
  };

  return (
    <div className="tutor-free-mode">
      {/* 주제 선택 영역 */}
      {!selectedTopic && (
        <div className="topic-selection">
          <h3>대화 주제를 선택하세요</h3>
          
          {/* 커스텀 주제 입력 부분 */}
          {showCustomTopicInput ? (
            <div className="custom-topic-input">
              <input
                type="text"
                value={customTopicInput}
                onChange={(e) => setCustomTopicInput(e.target.value)}
                placeholder="원하는 주제를 입력하세요..."
                onKeyDown={handleKeyDown}
                autoFocus
              />
              <div className="custom-topic-buttons">
                <button 
                  onClick={handleCustomTopicSubmit}
                  disabled={!customTopicInput.trim()}
                >
                  확인
                </button>
                <button onClick={() => setShowCustomTopicInput(false)}>
                  취소
                </button>
              </div>
            </div>
          ) : (
            <div className="topic-grid">
              {topics.map(topic => (
                <div 
                  key={topic.id} 
                  className="topic-card"
                  onClick={() => handleTopicSelect(topic)}
                >
                  <div className="topic-icon">{topic.icon}</div>
                  <div className="topic-name">{topic.name}</div>
                  <div className="topic-description">{topic.description}</div>
                </div>
              ))}
              <div 
                className="topic-card custom-topic"
                onClick={() => setShowCustomTopicInput(true)}
              >
                <div className="topic-icon">✏️</div>
                <div className="topic-name">주제 직접 입력</div>
                <div className="topic-description">원하는 주제를 직접 입력하세요</div>
              </div>
              <div 
                className="topic-card custom-topic"
                onClick={() => handleTopicSelect({ id: 'free', name: '자유 대화', icon: '💬', description: '아무 주제나 자유롭게 대화해요' })}
              >
                <div className="topic-icon">💬</div>
                <div className="topic-name">자유 대화</div>
                <div className="topic-description">아무 주제나 자유롭게 대화해요</div>
              </div>
            </div>
          )}
        </div>
      )}
      
      {/* 채팅 영역 */}
      <div className="chat-area">
        {selectedTopic && (
          <div className="selected-topic">
            <span className="topic-icon">{selectedTopic.icon}</span>
            <span className="topic-name">{selectedTopic.name}</span>
            <button 
              className="change-topic-button"
              onClick={handleChangeTopic}
            >
              주제 변경
            </button>
          </div>
        )}
        
        <div className="chat-container" ref={chatContainerRef} onScroll={handleScroll}>
          {messages.map((message, index) => (
            <div 
              key={index} 
              className={`chat-message ${message.role === 'user' ? 'user-message' : 
                message.role === 'system' ? 'system-message' : 'assistant-message'}`}
            >
              {message.role !== 'system' && (
                <div className="message-avatar">
                  {message.role === 'user' ? '👤' : '👨‍🏫'}
                </div>
              )}
              <div className="message-content">
                <div className="message-text">{message.content}</div>
                {message.role !== 'system' && (
                  <div className="message-time">
                    {new Date(message.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </div>
                )}
              </div>
              <div className="message-actions">
                {message.role === 'assistant' && (
                  <button 
                    className="speak-button"
                    onClick={() => speakText(message.content)}
                    disabled={isSpeaking}
                  >
                    {isSpeaking ? '🔊' : '🔈'}
                  </button>
                )}
                {message.role === 'user' && (
                  <button 
                    className="feedback-button"
                    onClick={() => requestFeedback(message)}
                    title="이 메시지에 대한 피드백 요청"
                  >
                    💬
                  </button>
                )}
              </div>
            </div>
          ))}
          
          {isTyping && (
            <div className="typing-indicator">
              <div className="typing-avatar">👨‍🏫</div>
              <div className="typing-name">AI 튜터</div>
              <div className="typing-dots">
                <div className="typing-dot"></div>
                <div className="typing-dot"></div>
                <div className="typing-dot"></div>
              </div>
            </div>
          )}
          
          {/* 스크롤 하단 버튼 (스크롤이 위로 올라갔을 때만 표시) */}
          {!autoScrollRef.current && (
            <button 
              className="scroll-bottom-button"
              onClick={() => {
                if (chatContainerRef.current) {
                  chatContainerRef.current.scrollTop = chatContainerRef.current.scrollHeight;
                  autoScrollRef.current = true;
                }
              }}
            >
              ↓
            </button>
          )}
        </div>
        
        {/* 새로운 피드백 모달 */}
        {feedbackRequested && (
          <div className="feedback-modal">
            <div className="feedback-modal-content">
              <div className="feedback-modal-header">
                <h3>언어 학습 피드백</h3>
                <button 
                  className="close-feedback-button"
                  onClick={cancelFeedback}
                >
                  ×
                </button>
              </div>
              
              <div className="feedback-language-selector">
                <label htmlFor="feedback-language">피드백 언어:</label>
                <select 
                  id="feedback-language" 
                  value={feedbackLanguage}
                  onChange={handleFeedbackLanguageChange}
                >
                  <option value="korean">한국어</option>
                  <option value="englishexpress">English</option>
                  <option value="japanese">日本語</option>
                  <option value={selectedLanguage}>
                    {languageNames[selectedLanguage]}
                  </option>
                </select>
              </div>
              
              <div className="feedback-message-preview">
                <div className="feedback-preview-label">입력한 메시지:</div>
                <div className="feedback-preview-text">
                  {feedbackForMessage?.content}
                </div>
              </div>
              
              {!feedbackText && !isFeedbackLoading && (
                <button 
                  className="generate-feedback-button"
                  onClick={generateLanguageFeedback}
                >
                  피드백 생성하기
                </button>
              )}
              
              {isFeedbackLoading && (
                <div className="feedback-loading">
                  피드백을 생성 중입니다...
                </div>
              )}
              
              {feedbackText && (
                <div className="feedback-result">
                  <div className="feedback-content">
                    {feedbackText}
                  </div>
                  <div className="feedback-actions">
                    <button 
                      className="regenerate-feedback-button"
                      onClick={generateLanguageFeedback}
                    >
                      다시 생성
                    </button>
                  </div>
                </div>
              )}
            </div>
          </div>
        )}
        
        {/* 입력 영역 */}
        <div className="input-area">
          <button 
            className={`voice-input-button ${isListening ? 'listening' : ''}`}
            onClick={toggleSpeechRecognition}
            disabled={isSpeaking || lockRef.current}
          >
            {isListening ? '🎤' : '🎤'}
          </button>
          
          {/* 언어 감지 표시 */}
          {detectedLanguage !== selectedLanguage && inputText.trim() !== '' && (
            <div className="input-language-indicator">
              <span className="detected-language">
                {languageNames[detectedLanguage]} 감지됨
              </span>
            </div>
          )}
          
          <textarea
            className="message-input"
            value={inputText}
            onChange={(e) => {
              setInputText(e.target.value);
              
              // 실시간 언어 감지
              if (e.target.value.trim() !== '') {
                const detectedLang = detectLanguage(e.target.value);
                setDetectedLanguage(detectedLang);
              }
            }}
            onKeyDown={handleKeyDown}
            placeholder="메시지를 입력하세요..."
            rows={2}
            disabled={lockRef.current}
          />
          <button 
            className="send-button"
            onClick={handleSendMessage}
            disabled={!inputText.trim() || lockRef.current || isTyping}
          >
            전송
          </button>
        </div>
      </div>
    </div>
  );
};

export default TutorFreeMode;