// TutorModeManager.js - 다자모드를 제거하고 자율모드만 사용하는 개선된 버전

import React, { useState, useEffect } from 'react';
import TutorFreeMode from './TutorFreeMode';
import './TutorMode.css';

const TutorModeManager = ({ apiKey, selectedLanguage, level, onClose }) => {
  const [showIntro, setShowIntro] = useState(true);
  const [resetKey, setResetKey] = useState(0); // 컴포넌트 강제 리셋을 위한 키
  
  // 5초 후 인트로 자동 닫기
  useEffect(() => {
    if (showIntro) {
      const timer = setTimeout(() => {
        setShowIntro(false);
      }, 5000);
      
      return () => clearTimeout(timer);
    }
  }, [showIntro]);
  
  // 언어가 변경될 때마다 컴포넌트 강제 리셋
  useEffect(() => {
    setResetKey(prevKey => prevKey + 1);
  }, [selectedLanguage]);

  // 인트로 화면 렌더링
  if (showIntro) {
    return (
      <div className="tutor-mode-container">
        <div className="tutor-intro">
          <div className="tutor-intro-content">
            <h1>튜터 모드에 오신 것을 환영합니다! 🎉</h1>
            <p>자유롭게 대화하면서 {selectedLanguage === 'korean' ? '한국어' : 
              selectedLanguage === 'japanese' ? '일본어' : '영어'}를 배워보세요.</p>
            
            <div className="tutor-intro-modes">
              <div className="tutor-intro-mode" onClick={() => setShowIntro(false)}>
                <div className="tutor-intro-icon">👨‍🏫</div>
                <h3>자율모드</h3>
                <p>자유롭게 대화하면서 언어를 배우는 모드입니다. 다양한 주제로 대화하며 실력을 향상시켜 보세요!</p>
              </div>
            </div>
            
            <button className="skip-intro-button" onClick={() => setShowIntro(false)}>
              시작하기
            </button>
          </div>
        </div>
      </div>
    );
  }
  
  return (
    <div className="tutor-mode-container">
      <div className="tutor-header">
        <h2 className="tutor-title">AI 튜터 모드</h2>
        <div className="mode-description">
          자유롭게 대화하면서 언어를 배우는 모드예요. 친구처럼 편하게 대화해요!
        </div>
      </div>
      
      <div className="tutor-content">
        <TutorFreeMode 
          key={`free-${resetKey}`}
          apiKey={apiKey} 
          selectedLanguage={selectedLanguage} 
          level={level} 
        />
      </div>
      
      <div className="tutor-footer">
        <button onClick={onClose} className="close-tutor-button">
          튜터 모드 종료
        </button>
      </div>
    </div>
  );
};

export default TutorModeManager;